+import { ComponentFixture, TestBed } from "@angular/core/testing";
+import { signal, WritableSignal } from "@angular/core";
+import { beforeEach, describe, expect, it, vi } from "vitest";
+
+import { DrawingVersionPanelComponent } from "./drawing-version-panel.component";
+import { DRAWING_VERSION_PANEL_QA } from "./drawing-version-panel-qa";
+import { DrawingViewerService } from "Drawing/services/drawing-viewer.service";
+import { DrawingVersionItem } from "Drawing/interfaces/DrawingVersionItem";
+import { detectChangesAndWhenStable } from "shared/testing/detect-changes-helpers";
+import { qaDom, type QaDom } from "shared/testing/by-qa-id";
+
+function createItem(overrides: Partial<DrawingVersionItem> = {}): DrawingVersionItem {
+    return {
+        drawingid: 1,
+        revisionnumber: "3",
+        drawingSetIssuedOn: "2025-01-10",
+        drawingSetName: "IFC",
+        isCurrent: false,
+        ...overrides,
+    };
+}
+
+describe("DrawingVersionPanelComponent", () => {
+    let fixture: ComponentFixture<DrawingVersionPanelComponent>;
+    let component: DrawingVersionPanelComponent;
+    let mockService: {
+        isVersionPanelOpen: WritableSignal<boolean>;
+        versionPanelPosition: WritableSignal<{ top: number; left: number }>;
+        drawingVersionItems: WritableSignal<DrawingVersionItem[]>;
+        closeVersionPanel: ReturnType<typeof vi.fn>;
+        onDrawingSelected: ReturnType<typeof vi.fn>;
+        settings: { revAbbreviation: string } | null;
+    };
+
+    beforeEach(async () => {
+        TestBed.resetTestingModule();
+        mockService = {
+            isVersionPanelOpen: signal(false),
+            versionPanelPosition: signal({ top: 100, left: 200 }),
+            drawingVersionItems: signal<DrawingVersionItem[]>([]),
+            closeVersionPanel: vi.fn(),
+            onDrawingSelected: vi.fn(),
+            settings: { revAbbreviation: "R" },
+        };
+
+        await TestBed.configureTestingModule({
+            imports: [DrawingVersionPanelComponent],
+            providers: [{ provide: DrawingViewerService, useValue: mockService }],
+        }).compileComponents();
+
+        fixture = TestBed.createComponent(DrawingVersionPanelComponent);
+        component = fixture.componentInstance;
+    });
+
+    describe("Business Logic", () => {
+        beforeEach(async () => {
+            await detectChangesAndWhenStable(fixture);
+        });
+
+        it("should create", () => {
+            expect(component).toBeTruthy();
+        });
+
+        it("selectVersion closes the panel", () => {
+            component["selectVersion"](createItem());
+            expect(mockService.closeVersionPanel).toHaveBeenCalled();
+        });
+
+        it("selectVersion navigates to drawing when item is not current", () => {
+            const item = createItem({ drawingid: 42, isCurrent: false });
+            component["selectVersion"](item);
+            expect(mockService.onDrawingSelected).toHaveBeenCalledWith(42, null);
+        });
+
+        it("selectVersion does not navigate when item is current", () => {
+            component["selectVersion"](createItem({ isCurrent: true }));
+            expect(mockService.onDrawingSelected).not.toHaveBeenCalled();
+        });
+
+        it("selectVersion still closes panel when item is current", () => {
+            component["selectVersion"](createItem({ isCurrent: true }));
+            expect(mockService.closeVersionPanel).toHaveBeenCalled();
+        });
+
+        it("formatLabel uses revAbbreviation from settings with date and set name", () => {
+            const item = createItem({ revisionnumber: "3", drawingSetIssuedOn: "2025-01-10", drawingSetName: "IFC" });
+            expect(component["formatLabel"](item)).toBe("R 3 (2025-01-10) - IFC");
+        });
+
+        it("onDocumentClick closes panel on outside click", () => {
+            mockService.isVersionPanelOpen.set(true);
+            fixture.detectChanges();
+
+            const event = new MouseEvent("click", { bubbles: true });
+            Object.defineProperty(event, "target", { value: document.body });
+            component["onDocumentClick"](event);
+
+            expect(mockService.closeVersionPanel).toHaveBeenCalled();
+        });
+
+        it("onDocumentClick does NOT close when click is inside the panel element", () => {
+            mockService.isVersionPanelOpen.set(true);
+            mockService.drawingVersionItems.set([createItem()]);
+            fixture.detectChanges();
+
+            const panelEl = fixture.nativeElement.querySelector(".drawing-versions-dropdown") as HTMLElement;
+            const event = new MouseEvent("click", { bubbles: true });
+            Object.defineProperty(event, "target", { value: panelEl });
+            component["onDocumentClick"](event);
+
+            expect(mockService.closeVersionPanel).not.toHaveBeenCalled();
+        });
+
+        it("onDocumentClick does NOT close when click is inside the toolbar version button", () => {
+            mockService.isVersionPanelOpen.set(true);
+            fixture.detectChanges();
+
+            const btn = document.createElement("li");
+            btn.setAttribute("data-toolbar-value", "drawingversion");
+            document.body.appendChild(btn);
+
+            const event = new MouseEvent("click", { bubbles: true });
+            Object.defineProperty(event, "target", { value: btn });
+            component["onDocumentClick"](event);
+
+            document.body.removeChild(btn);
+            expect(mockService.closeVersionPanel).not.toHaveBeenCalled();
+        });
+    });
+
+    describe("UI render test", () => {
+        let qa: QaDom<DrawingVersionPanelComponent>;
+
+        beforeEach(async () => {
+            mockService.isVersionPanelOpen.set(true);
+            mockService.versionPanelPosition.set({ top: 100, left: 200 });
+            mockService.drawingVersionItems.set([
+                createItem({ drawingid: 1, revisionnumber: "1", isCurrent: true }),
+                createItem({ drawingid: 2, revisionnumber: "2", isCurrent: false }),
+            ]);
+            await detectChangesAndWhenStable(fixture);
+            fixture.detectChanges();
+            qa = qaDom(fixture);
+        });
+
+        it("does not render dropdown when panel is closed", async () => {
+            mockService.isVersionPanelOpen.set(false);
+            await detectChangesAndWhenStable(fixture);
+            fixture.detectChanges();
+            expect(qaDom(fixture).query(DRAWING_VERSION_PANEL_QA.dropdown)).toBeNull();
+        });
+
+        it("renders dropdown when panel is open", () => {
+            expect(qa.query(DRAWING_VERSION_PANEL_QA.dropdown)).not.toBeNull();
+        });
+
+        it("positions dropdown via top and left styles", () => {
+            const el = qa.query(DRAWING_VERSION_PANEL_QA.dropdown)!.nativeElement as HTMLElement;
+            expect(el.style.top).toBe("100px");
+            expect(el.style.left).toBe("200px");
+        });
+
+        it("renders one row per drawingVersionItems entry", () => {
+            expect(qa.query(DRAWING_VERSION_PANEL_QA.versionItem(1))).not.toBeNull();
+            expect(qa.query(DRAWING_VERSION_PANEL_QA.versionItem(2))).not.toBeNull();
+        });
+
+        it("applies .current CSS class to the current item", () => {
+            const el = qa.query(DRAWING_VERSION_PANEL_QA.versionItem(1))!.nativeElement as HTMLElement;
+            expect(el.classList.contains("current")).toBe(true);
+        });
+
+        it("does NOT apply .current CSS class to non-current items", () => {
+            const el = qa.query(DRAWING_VERSION_PANEL_QA.versionItem(2))!.nativeElement as HTMLElement;
+            expect(el.classList.contains("current")).toBe(false);
+        });
+
+        it("clicking an item calls selectVersion", () => {
+            const spy = vi.spyOn(component as never, "selectVersion");
+            qa.click(DRAWING_VERSION_PANEL_QA.versionItem(1));
+            expect(spy).toHaveBeenCalled();
+        });
+
+        it("item label text matches formatLabel output", () => {
+            const item = createItem({ drawingid: 1, revisionnumber: "1", drawingSetIssuedOn: "2025-01-10", drawingSetName: "IFC", isCurrent: true });
+            const expected = component["formatLabel"](item);
+            expect(qa.text(DRAWING_VERSION_PANEL_QA.versionItem(1))?.trim()).toBe(expected);
+        });
+    });
+});

